import sys

def solve(nums):
    pos = 0
    for n in nums:
        if n != 0:
            nums[pos] = n; pos += 1
    for i in range(pos, len(nums)): nums[i] = 0
    return ' '.join(map(str, nums))

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data: sys.exit(0)
    arr = list(map(int, data))
    print(solve(arr))

