#include <iostream>
#include <vector>
using namespace std;

void solve(vector<int>& nums) {
    int pos = 0;
    for (int n : nums) if (n != 0) nums[pos++] = n;
    while (pos < nums.size()) nums[pos++] = 0;
}

int main() {
    int val; vector<int> arr;
    while (cin >> val) arr.push_back(val);
    solve(arr);
    for (int i = 0; i < arr.size(); i++) { if (i) cout << ' '; cout << arr[i]; }
    cout << endl; return 0;
}

